{{#compactCards}}
/* Kill Jira's transition:all */
[data-testid="platform-board-kit.ui.card.card"],
[data-testid="platform-board-kit.ui.card.card"] *,
[data-testid="software-board.board-container.board.card-container.card-with-icc"] { transition: none !important; }
/* Compact: force 12px on li>div AND all nested divs/spans — Jira sets explicit 14px on title divs that overrides inheritance */
[data-testid="software-board.board-container.board.virtual-board.fast-virtual-list.fast-virtual-list-wrapper"] > li > div,
[data-testid="software-board.board-container.board.virtual-board.fast-virtual-list.fast-virtual-list-wrapper"] > li div,
[data-testid="software-board.board-container.board.virtual-board.fast-virtual-list.fast-virtual-list-wrapper"] > li span,
[data-testid="software-board.board-container.board.virtual-board.fast-virtual-list.fast-virtual-list-wrapper"] > li a { font-size: 12px !important; line-height: 16px !important; transition: none !important; }
[data-testid="platform-board-kit.ui.card.card"] { margin-bottom: 1px !important; }
/* Compact inner padding — applies once inner structure renders */
[data-testid="platform-card.ui.card.focus-container"] + div > div > div { padding: 6px 8px !important; }
[data-component-selector="platform-card.ui.card.card-content.content-section"]:not([data-testid="platform-card.ui.card.card-content.footer"]) { margin-bottom: 2px !important; }
[data-testid="issue-field-summary-inline-edit.ui.read"] { font-size: 12px !important; line-height: 16px !important; padding: 1px 0 !important; }
[data-testid="issue-field-summary-inline-edit.ui.read"] span { padding-right: 16px !important; }
[data-testid="platform-card.ui.card.card-content.footer"] { padding-top: 0 !important; margin-top: 2px !important; }
[data-testid="platform-card.ui.card.card-content.footer"] img { width: 14px !important; height: 14px !important; }
[data-testid="platform-card.common.ui.key.key"] { font-size: 11px !important; }
{{/compactCards}}
{{#ultraCompact}}
/* Ultra-compact: minimal padding, single-line titles, hide key and avatar */
[data-testid="platform-card.ui.card.focus-container"] + div > div > div { padding: 3px 6px !important; }
[data-component-selector="platform-card.ui.card.card-content.content-section"]:not([data-testid="platform-card.ui.card.card-content.footer"]) { margin-bottom: 0 !important; }
[data-testid="issue-field-summary-inline-edit.ui.read"] { font-size: 11px !important; line-height: 14px !important; padding: 0 !important; }
[data-testid="issue-field-summary-inline-edit.ui.read"] span { -webkit-line-clamp: 1 !important; display: -webkit-box !important; -webkit-box-orient: vertical !important; overflow: hidden !important; padding-right: 4px !important; }
[data-testid="platform-card.common.ui.key.key"] { display: none !important; }
[data-testid="software-board.common.fields.assignee-field-static.avatar-wrapper"] { display: none !important; }
[data-testid="platform-card.ui.card.card-content.footer"] { margin-top: 0 !important; }
[data-testid="platform-card.ui.card.card-content.footer"] img { width: 12px !important; height: 12px !important; }
{{/ultraCompact}}
{{#stickyHeaders}}
/* Sticky column headers */
[data-testid="platform-board-kit.common.ui.column-header.header.column-header-container"] { position: sticky !important; top: 0 !important; z-index: 10 !important; background: var(--ds-surface, #1d1e20) !important; }
{{/stickyHeaders}}
{{#equalColumns}}
/* Equal-width columns */
[data-testid="platform-board-kit.ui.column.draggable-column.styled-wrapper"] { flex: 1 1 0 !important; min-width: 200px !important; max-width: none !important; }
{{/equalColumns}}
{{#cardCountBadges}}
/* Prominent card count badges */
[data-testid="platform-board-kit.common.ui.column-header.editable-title.column-title.column-title"] + div { background: var(--ds-background-neutral, #333) !important; border-radius: 10px !important; padding: 1px 7px !important; font-weight: 600 !important; font-size: 11px !important; }
{{/cardCountBadges}}

