if (api.options.fullScreenMode) {
  (function() {
    var STORAGE_KEY = '__domo_jira_fullscreen';
    var isFullScreen = false;
    try { isFullScreen = localStorage.getItem(STORAGE_KEY) === 'true'; } catch(e) {}

    var styleEl = document.createElement('style');
    styleEl.id = '__domo_jira_fullscreen_style';
    document.head.appendChild(styleEl);
    api.onCleanup(function() { if (styleEl.parentNode) styleEl.parentNode.removeChild(styleEl); });

    var fullScreenCSS = [
      '[data-testid="page-layout.sidebar"] { display: none !important; width: 0 !important; }',
      '[data-testid="sidebar-entry.panel-splitter-container"] { display: none !important; }',
      '[data-testid="sidebar-entry.panel-splitter"] { display: none !important; }',
      '[data-testid="horizontal-nav.ui.content.horizontal-nav"] { display: none !important; }',
      '[data-testid="horizontal-nav-header.ui.project-header.header"] { display: none !important; }',
      '[data-testid="page-layout.main"] { margin-left: 0 !important; }',
      '[data-testid="software-board.board"] { height: calc(100vh - 80px) !important; }'
    ].join('\n');

    function applyFullScreen(on) {
      isFullScreen = on;
      styleEl.textContent = on ? fullScreenCSS : '';
      try { localStorage.setItem(STORAGE_KEY, on ? 'true' : 'false'); } catch(e) {}
      if (btn) btn.textContent = on ? 'Exit Focus' : 'Focus Mode';
    }

    var btn = document.createElement('button');
    btn.textContent = isFullScreen ? 'Exit Focus' : 'Focus Mode';
    btn.style.cssText = 'position:fixed;bottom:16px;right:16px;z-index:99999;padding:6px 14px;border-radius:6px;border:1px solid var(--ds-border,#444);background:var(--ds-surface-overlay,#2c2d30);color:var(--ds-text,#dee1e6);font-size:12px;cursor:pointer;font-family:inherit;box-shadow:0 2px 8px rgba(0,0,0,0.3);transition:opacity 0.2s;opacity:0.7;';
    btn.addEventListener('mouseenter', function() { btn.style.opacity = '1'; });
    btn.addEventListener('mouseleave', function() { btn.style.opacity = '0.7'; });
    btn.addEventListener('click', function() { applyFullScreen(!isFullScreen); });
    document.body.appendChild(btn);
    api.onCleanup(function() { if (btn.parentNode) btn.parentNode.removeChild(btn); });

    function onKeyDown(e) {
      if (e.altKey && e.key === 'f' && !e.target.closest('input, textarea, [contenteditable]')) {
        e.preventDefault();
        applyFullScreen(!isFullScreen);
      }
    }
    document.addEventListener('keydown', onKeyDown);
    api.onCleanup(function() { document.removeEventListener('keydown', onKeyDown); });

    if (isFullScreen) applyFullScreen(true);
  })();
}
